$subf = null;
$find = array();
preg_match_all("/\(Subcategory~equals~(.+)\)/U",postvalue("f"),$find);
if(count($find[1]) > 0 && isset($find[1][0]))
	$subf  = $find[1][0];
$cat_rs = DB::Select("newscategory");
$links_arr = array();
$main_link = GetTableLink("newsmain","list");
$links_arr["all"] = array("link" => $main_link,"label" => "SEMUA", "class" => "","subcategory" => array() );
while($cat = $cat_rs->fetchAssoc()){
	$links_arr[$cat["CategoryName"]] = array("link" => $main_link."?f=(Category~equals~".rawurlencode($cat["CategoryName"]).")","label" => $cat["CategoryName"], "class" => "","subcategory" => array() );
	$subcat_rs = DB::Select("newssubcategory",array("Category" => $cat["CategoryName"]));
	while($subcat = $subcat_rs->fetchAssoc()){
				$subcat_count_rs = DB::Select("newsmain",array("Subcategory" => $subcat["SubcategoryName"] ));
				$subcat_count = $subcat_count_rs->fetchAssoc();
				if(!$subcat_count) continue;
				$links_arr[$cat["CategoryName"]]["subcategory"][$subcat["SubcategoryID"]] = array("link" => $main_link."?f=(Subcategory~equals~".rawurlencode($subcat["SubcategoryName"]).")","label" => $subcat["SubcategoryName"], "class" => "" );
				if($subf === $subcat["SubcategoryName"]) {
					$links_arr[$cat["CategoryName"]]["subcategory"][$subcat["SubcategoryID"]]["class"] = "active";
					$links_arr[$cat["CategoryName"]]["class"] = "active";
				}
	}

}
$catf = null;
$find = array();
preg_match_all("/\(Category~equals~(.+)\)/U",postvalue("f"),$find);
if(count($find[1]) > 0 && isset($find[1][0]))
{
	$catf = $find[1][0];
	$links_arr[$find[1][0]]["class"] = "active";
}

if(is_null($subf) && is_null($catf)) 
	$links_arr["all"]["class"] = "active";
foreach($links_arr as $link){
	echo "<span class='".$link["class"]."'><a href='".$link["link"]."'>".$link["label"]."</a>";
	if(count($link["subcategory"])){
		echo "<ul class='newssubcategory'>";
		foreach($link["subcategory"] as $subcategory)
			echo "<li class='".$subcategory["class"]."'><a href='".$subcategory["link"]."'>".$subcategory["label"]."</a></li>";
		echo "</ul>";
	}
	echo  "</span>";
}
